 91→private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
 92→    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
 93→    val totalFields = accumulator + fieldsCount
 94→    val superClass = superclass ?: return totalFields
 95→    return superClass.fieldsCount(totalFields)
