102→private object WeakMapCtorCache : CtorCache() {
103→    private val cacheLock = ReentrantReadWriteLock()
104→    private val exceptionCtors: WeakHashMap<Class<out Throwable>, Ctor> = WeakHashMap()
105→
106→    override fun get(key: Class<out Throwable>): Ctor {
107→        cacheLock.read { exceptionCtors[key]?.let { return it } }
108→        cacheLock.write {
109→            exceptionCtors[key]?.let { return it }
110→            return createConstructor(key).also { exceptionCtors[key] = it }
111→        }
112→    }
113→}
