115→@IgnoreJreRequirement
116→private object ClassValueCtorCache : CtorCache() {
117→    private val cache = object : ClassValue<Ctor>() {
118→        override fun computeValue(type: Class<*>?): Ctor {
119→            @Suppress("UNCHECKED_CAST")
120→            return createConstructor(type as Class<out Throwable>)
121→        }
122→    }
123→
124→    override fun get(key: Class<out Throwable>): Ctor = cache.get(key)
125→}
