package kotlinx.coroutines.exceptions

import kotlinx.coroutines.*
import org.junit.Test
import kotlin.test.*

/**
 * Test for issue: recoverStackTrace causes nested exceptions
 * When throwing an exception in a coroutine scope it sometimes becomes nested one level too deep.
 */
class NestedExceptionTest : TestBase() {

    @Test
    fun testNestedException() = runTest {
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedException, "Expected NestedException but got ${ex.javaClass.name}")
        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass?.name}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    @Test
    fun testNestedExceptionWithMessageConstructorFirst() = runTest {
        // Test with the constructor order as originally reported (message first, cause second)
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedExceptionMessageFirst(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionMessageFirst, "Expected NestedExceptionMessageFirst but got ${ex.javaClass.name}")
        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass?.name}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    @Test
    fun testNestedExceptionWithCauseConstructorFirst() = runTest {
        // Test with cause constructor first (this was the workaround that worked before)
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedExceptionCauseFirst(IllegalStateException("ERROR"))
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedExceptionCauseFirst, "Expected NestedExceptionCauseFirst but got ${ex.javaClass.name}")
        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass?.name}")
        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
    }

    @Test
    fun testNestedExceptionWithMessage() = runTest {
        // Test that message-only constructor also works
        val result = runCatching {
            coroutineScope<Unit> {
                throw NestedException("TEST_MESSAGE")
            }
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedException, "Expected NestedException but got ${ex.javaClass.name}")
        assertEquals("TEST_MESSAGE", ex.message)
    }

    @Test
    fun testNestedExceptionWithAsync() = runTest {
        // Test with async/await pattern
        val deferred = async<Unit>(SupervisorJob() + Dispatchers.Unconfined) {
            throw NestedException(IllegalStateException("ASYNC_ERROR"))
        }

        val result = runCatching {
            deferred.await()
        }
        val ex = result.exceptionOrNull() ?: error("Expected to fail")
        assertTrue(ex is NestedException, "Expected NestedException but got ${ex.javaClass.name}")
        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass?.name}")
        assertEquals("ASYNC_ERROR", (ex.cause as IllegalStateException).message)
    }
}

/**
 * Exception class with constructors in order: message, cause, empty
 * This order previously caused the bug where the String constructor was picked instead of Throwable constructor.
 */
class NestedException : RuntimeException {
    constructor(message: String) : super(message)
    constructor(cause: Throwable) : super(cause)
    constructor() : super()
}

/**
 * Exception class with constructors in order: message, cause, empty
 * Same as NestedException but explicitly named to show the issue.
 */
class NestedExceptionMessageFirst : RuntimeException {
    constructor(message: String) : super(message)
    constructor(cause: Throwable) : super(cause)
    constructor() : super()
}

/**
 * Exception class with constructors in order: cause, message, empty
 * This order was the workaround that worked before the fix.
 */
class NestedExceptionCauseFirst : RuntimeException {
    constructor(cause: Throwable) : super(cause)
    constructor(message: String) : super(message)
    constructor() : super()
}
