 10→import java.util.concurrent.locks.*
 11→import kotlin.concurrent.*
 12→
 13→private val throwableFields = Throwable::class.java.fieldsCountOrDefault(-1)
 14→private typealias Ctor = (Throwable) -> Throwable?
 15→
 16→private val ctorCache = try {
 17→    if (ANDROID_DETECTED) WeakMapCtorCache
 18→    else ClassValueCtorCache
 19→} catch (e: Throwable) {
 20→    // Fallback on Java 6 or exotic setups
 21→    WeakMapCtorCache
 22→}
 23→
 24→@Suppress("UNCHECKED_CAST")
 25→internal fun <E : Throwable> tryCopyException(exception: E): E? {
 26→    // Fast path for CopyableThrowable
 27→    if (exception is CopyableThrowable<*>) {
 28→        return runCatching { exception.createCopy() as E? }.getOrNull()
 29→    }
 30→    return ctorCache.get(exception.javaClass).invoke(exception) as E?
 31→}
 32→
 33→private fun <E : Throwable> createConstructor(clz: Class<E>): Ctor {
 34→    val nullResult: Ctor = { null } // Pre-cache class
 35→    // Skip reflective copy if an exception has additional fields (that are usually populated in user-defined constructors)
 36→    if (throwableFields != clz.fieldsCountOrDefault(0)) return nullResult
 37→    /*
 38→    * Try to reflectively find constructor(), constructor(message, cause), constructor(cause) or constructor(message).
 39→    * Exceptions are shared among coroutines, so we should copy exception before recovering current stacktrace.
 40→    */
 41→    val constructors = clz.constructors.sortedByDescending { ctor ->
 42→        // Sort by parameter count first, then by preference: (String, Throwable) > Throwable > String > others
 43→        val p = ctor.parameterTypes
 44→        when (p.size) {
 45→            2 -> when {
 46→                p[0] == String::class.java && p[1] == Throwable::class.java -> 4
 47→                else -> 0
 48→            }
 49→            1 -> when (p[0]) {
 50→                Throwable::class.java -> 3
 51→                String::class.java -> 2
 52→                else -> 0
 53→            }
 54→            0 -> 1
 55→            else -> 0
 56→        }
 57→    }
 58→    for (constructor in constructors) {
 59→        val result = createSafeConstructor(constructor)
 60→        if (result != null) return result
 61→    }
 62→    return nullResult
 63→}
 64→
 65→private fun createSafeConstructor(constructor: Constructor<*>): Ctor? {
 66→    val p = constructor.parameterTypes
 67→    return when (p.size) {
 68→        2 -> when {
 69→            p[0] == String::class.java && p[1] == Throwable::class.java ->
 70→                safeCtor { e -> constructor.newInstance(e.message, e) as Throwable }
 71→            else -> null
 72→        }
 73→        1 -> when (p[0]) {
 74→            Throwable::class.java ->
 75→                safeCtor { e -> constructor.newInstance(e) as Throwable }
 76→            String::class.java ->
 77→                safeCtor { e -> (constructor.newInstance(e.message) as Throwable).also { it.initCause(e) } }
 78→            else -> null
 79→        }
 80→        0 -> safeCtor { e -> (constructor.newInstance() as Throwable).also { it.initCause(e) } }
 81→        else -> null
 82→    }
 83→}
 84→
 85→private inline fun safeCtor(crossinline block: (Throwable) -> Throwable): Ctor =
 86→    { e -> runCatching { block(e) }.getOrNull() }
 87→
 88→private fun Class<*>.fieldsCountOrDefault(defaultValue: Int) =
 89→    kotlin.runCatching { fieldsCount() }.getOrDefault(defaultValue)
 90→
 91→private tailrec fun Class<*>.fieldsCount(accumulator: Int = 0): Int {
 92→    val fieldsCount = declaredFields.count { !Modifier.isStatic(it.modifiers) }
 93→    val totalFields = accumulator + fieldsCount
 94→    val superClass = superclass ?: return totalFields
 95→    return superClass.fieldsCount(totalFields)
 96→}
 97→
 98→internal abstract class CtorCache {
 99→    abstract fun get(key: Class<out Throwable>): Ctor
100→}
101→
102→private object WeakMapCtorCache : CtorCache() {
103→    private val cacheLock = ReentrantReadWriteLock()
104→    private val exceptionCtors: WeakHashMap<Class<out Throwable>, Ctor> = WeakHashMap()
105→
106→    override fun get(key: Class<out Throwable>): Ctor {
107→        cacheLock.read { exceptionCtors[key]?.let { return it } }
108→        cacheLock.write {
109→            exceptionCtors[key]?.let { return it }
110→            return createConstructor(key).also { exceptionCtors[key] = it }
111→        }
112→    }
113→}
114→
115→@IgnoreJreRequirement
116→private object ClassValueCtorCache : CtorCache() {
117→    private val cache = object : ClassValue<Ctor>() {
118→        override fun computeValue(type: Class<*>?): Ctor {
119→            @Suppress("UNCHECKED_CAST")
120→            return createConstructor(type as Class<out Throwable>)
121→        }
122→    }
123→
124→    override fun get(key: Class<out Throwable>): Ctor = cache.get(key)
125→}
