 11→/**
 12→ * Test for issue: recoverStackTrace causes nested exceptions
 13→ * When throwing an exception in a coroutine scope it sometimes becomes nested one level too deep.
 14→ */
 15→class NestedExceptionTest : TestBase() {
 16→
 17→    @Test
 18→    fun testNestedException() = runTest {
 19→        val result = runCatching {
 20→            coroutineScope<Unit> {
 21→                throw NestedException(IllegalStateException("ERROR"))
 22→            }
 23→        }
 24→        val ex = result.exceptionOrNull() ?: error("Expected to fail")
 25→        assertTrue(ex is NestedException, "Expected NestedException but got ${ex.javaClass.name}")
 26→        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass?.name}")
 27→        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
 28→    }
 29→
 30→    @Test
 31→    fun testNestedExceptionWithMessageConstructorFirst() = runTest {
 32→        // Test with the constructor order as originally reported (message first, cause second)
 33→        val result = runCatching {
 34→            coroutineScope<Unit> {
 35→                throw NestedExceptionMessageFirst(IllegalStateException("ERROR"))
 36→            }
 37→        }
 38→        val ex = result.exceptionOrNull() ?: error("Expected to fail")
 39→        assertTrue(ex is NestedExceptionMessageFirst, "Expected NestedExceptionMessageFirst but got ${ex.javaClass.name}")
 40→        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass?.name}")
 41→        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
 42→    }
 43→
 44→    @Test
 45→    fun testNestedExceptionWithCauseConstructorFirst() = runTest {
 46→        // Test with cause constructor first (this was the workaround that worked before)
 47→        val result = runCatching {
 48→            coroutineScope<Unit> {
 49→                throw NestedExceptionCauseFirst(IllegalStateException("ERROR"))
 50→            }
 51→        }
 52→        val ex = result.exceptionOrNull() ?: error("Expected to fail")
 53→        assertTrue(ex is NestedExceptionCauseFirst, "Expected NestedExceptionCauseFirst but got ${ex.javaClass.name}")
 54→        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass?.name}")
 55→        assertEquals("ERROR", (ex.cause as IllegalStateException).message)
 56→    }
 57→
 58→    @Test
 59→    fun testNestedExceptionWithMessage() = runTest {
 60→        // Test that message-only constructor also works
 61→        val result = runCatching {
 62→            coroutineScope<Unit> {
 63→                throw NestedException("TEST_MESSAGE")
 64→            }
 65→        }
 66→        val ex = result.exceptionOrNull() ?: error("Expected to fail")
 67→        assertTrue(ex is NestedException, "Expected NestedException but got ${ex.javaClass.name}")
 68→        assertEquals("TEST_MESSAGE", ex.message)
 69→    }
 70→
 71→    @Test
 72→    fun testNestedExceptionWithAsync() = runTest {
 73→        // Test with async/await pattern
 74→        val deferred = async<Unit>(SupervisorJob() + Dispatchers.Unconfined) {
 75→            throw NestedException(IllegalStateException("ASYNC_ERROR"))
 76→        }
 77→
 78→        val result = runCatching {
 79→            deferred.await()
 80→        }
 81→        val ex = result.exceptionOrNull() ?: error("Expected to fail")
 82→        assertTrue(ex is NestedException, "Expected NestedException but got ${ex.javaClass.name}")
 83→        assertTrue(ex.cause is IllegalStateException, "Expected IllegalStateException cause but got ${ex.cause?.javaClass?.name}")
 84→        assertEquals("ASYNC_ERROR", (ex.cause as IllegalStateException).message)
 85→    }
 86→}
