 88→/**
 89→ * Exception class with constructors in order: message, cause, empty
 90→ * This order previously caused the bug where the String constructor was picked instead of Throwable constructor.
 91→ */
 92→class NestedException : RuntimeException {
 93→    constructor(message: String) : super(message)
 94→    constructor(cause: Throwable) : super(cause)
 95→    constructor() : super()
 96→}
 97→
 98→/**
 99→ * Exception class with constructors in order: message, cause, empty
100→ * Same as NestedException but explicitly named to show the issue.
101→ */
102→class NestedExceptionMessageFirst : RuntimeException {
103→    constructor(message: String) : super(message)
104→    constructor(cause: Throwable) : super(cause)
105→    constructor() : super()
106→}
107→
108→/**
109→ * Exception class with constructors in order: cause, message, empty
110→ * This order was the workaround that worked before the fix.
111→ */
112→class NestedExceptionCauseFirst : RuntimeException {
113→    constructor(cause: Throwable) : super(cause)
114→    constructor(message: String) : super(message)
115→    constructor() : super()
116→}
